import{_ as i,c as o,o as t,a2 as a}from"./chunks/framework.CIiVzG-O.js";const d=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md","lastUpdated":1776396452000}'),s={name:"guide/troubleshooting.md"};function r(n,e,l,h,p,c){return t(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><h2 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common Issues&quot;">​</a></h2><h3 id="application-won-t-start" tabindex="-1">Application Won&#39;t Start <a class="header-anchor" href="#application-won-t-start" aria-label="Permalink to &quot;Application Won&#39;t Start&quot;">​</a></h3><p><strong>Symptoms</strong>: Nicasa fails to launch or crashes immediately</p><p><strong>Solutions</strong>:</p><ol><li>Ensure you&#39;re running macOS 10.13 or later</li><li>Check that you have at least 4GB of RAM</li><li>Restart your Mac</li><li>Reinstall Nicasa from the Mac App Store</li><li>Check for conflicting applications</li></ol><h3 id="screenshots-not-working" tabindex="-1">Screenshots Not Working <a class="header-anchor" href="#screenshots-not-working" aria-label="Permalink to &quot;Screenshots Not Working&quot;">​</a></h3><p><strong>Symptoms</strong>: Screenshot functionality doesn&#39;t work</p><p><strong>Solutions</strong>:</p><ol><li><strong>Grant Screen Recording Permission</strong>: <ul><li>Go to System Settings &gt; Privacy &amp; Security &gt; Screen Recording</li><li>Check the box next to Nicasa</li><li>Restart Nicasa</li></ul></li><li>Ensure no other screenshot tools are running</li><li>Try restarting your Mac</li></ol><h3 id="chrome-extension-not-working" tabindex="-1">Chrome Extension Not Working <a class="header-anchor" href="#chrome-extension-not-working" aria-label="Permalink to &quot;Chrome Extension Not Working&quot;">​</a></h3><p><strong>Symptoms</strong>: Extension doesn&#39;t appear or doesn&#39;t extract images</p><p><strong>Solutions</strong>:</p><ol><li>Ensure the extension is enabled in Chrome</li><li>Check that you&#39;re using a compatible version of Chrome</li><li>Try refreshing the webpage</li><li>Reinstall the extension</li><li>Clear browser cache and cookies</li></ol><h3 id="images-not-loading" tabindex="-1">Images Not Loading <a class="header-anchor" href="#images-not-loading" aria-label="Permalink to &quot;Images Not Loading&quot;">​</a></h3><p><strong>Symptoms</strong>: Thumbnails don&#39;t appear or images fail to open</p><p><strong>Solutions</strong>:</p><ol><li>Check file permissions on the image files</li><li>Ensure the images aren&#39;t corrupted</li><li>Verify the format is supported (JPEG, PNG, GIF, BMP, TIFF, WebP)</li><li>Try opening the folder again</li><li>Restart Nicasa</li></ol><h3 id="slow-performance" tabindex="-1">Slow Performance <a class="header-anchor" href="#slow-performance" aria-label="Permalink to &quot;Slow Performance&quot;">​</a></h3><p><strong>Symptoms</strong>: Application is sluggish or thumbnails load slowly</p><p><strong>Solutions</strong>:</p><ol><li>Close other memory-intensive applications</li><li>Ensure adequate free RAM (8GB recommended)</li><li>Reduce thumbnail grid size in preferences</li><li>Clear application cache</li><li>Restart your Mac</li></ol><h3 id="ai-editor-not-working" tabindex="-1">AI Editor Not Working <a class="header-anchor" href="#ai-editor-not-working" aria-label="Permalink to &quot;AI Editor Not Working&quot;">​</a></h3><p><strong>Symptoms</strong>: AI editing tools are unavailable or not functioning</p><p><strong>Solutions</strong>:</p><ol><li>Ensure you have a stable internet connection (for some features)</li><li>Check that your Mac meets the minimum requirements</li><li>Restart Nicasa</li><li>Update to the latest version</li><li>Contact support if the issue persists</li></ol><h3 id="permission-problems" tabindex="-1">Permission Problems <a class="header-anchor" href="#permission-problems" aria-label="Permalink to &quot;Permission Problems&quot;">​</a></h3><p><strong>Symptoms</strong>: App requests permissions or certain features don&#39;t work</p><p><strong>Solutions</strong>:</p><ol><li><strong>Screen Recording</strong>: System Settings &gt; Privacy &amp; Security &gt; Screen Recording</li><li><strong>Accessibility</strong>: System Settings &gt; Privacy &amp; Security &gt; Accessibility (for overlay mode)</li><li><strong>Files and Folders</strong>: System Settings &gt; Privacy &amp; Security &gt; Files and Folders</li><li>Restart Nicasa after granting permissions</li></ol><h3 id="overlay-mode-issues" tabindex="-1">Overlay Mode Issues <a class="header-anchor" href="#overlay-mode-issues" aria-label="Permalink to &quot;Overlay Mode Issues&quot;">​</a></h3><p><strong>Symptoms</strong>: Transparent overlay mode doesn&#39;t work properly</p><p><strong>Solutions</strong>:</p><ol><li>Grant Accessibility permission in System Settings</li><li>Ensure no other overlay tools are running</li><li>Try toggling overlay mode off and on</li><li>Restart Nicasa</li></ol><h2 id="error-messages" tabindex="-1">Error Messages <a class="header-anchor" href="#error-messages" aria-label="Permalink to &quot;Error Messages&quot;">​</a></h2><h3 id="screen-recording-permission-required" tabindex="-1">&quot;Screen Recording Permission Required&quot; <a class="header-anchor" href="#screen-recording-permission-required" aria-label="Permalink to &quot;&quot;Screen Recording Permission Required&quot;&quot;">​</a></h3><p><strong>Solution</strong>: Grant screen recording permission as described above in the Screenshots section.</p><h3 id="failed-to-load-image" tabindex="-1">&quot;Failed to Load Image&quot; <a class="header-anchor" href="#failed-to-load-image" aria-label="Permalink to &quot;&quot;Failed to Load Image&quot;&quot;">​</a></h3><p><strong>Possible Causes</strong>:</p><ul><li>File is corrupted</li><li>Unsupported format</li><li>File permissions issue</li><li>File is too large</li></ul><p><strong>Solutions</strong>:</p><ol><li>Try opening the file with Preview.app to verify it&#39;s valid</li><li>Convert to a supported format</li><li>Check file permissions</li><li>Ensure file size is reasonable</li></ol><h3 id="extension-not-responding" tabindex="-1">&quot;Extension Not Responding&quot; <a class="header-anchor" href="#extension-not-responding" aria-label="Permalink to &quot;&quot;Extension Not Responding&quot;&quot;">​</a></h3><p><strong>Solution</strong>: Refresh the webpage and try again. If persistent, reinstall the extension.</p><h2 id="getting-help" tabindex="-1">Getting Help <a class="header-anchor" href="#getting-help" aria-label="Permalink to &quot;Getting Help&quot;">​</a></h2><p>If you continue to experience issues:</p><ol><li>Check this troubleshooting guide</li><li>Visit our <a href="/guide/faq.html">FAQ</a></li><li>Submit an issue on <a href="https://github.com/nicasa-app/nicasa-support/issues" target="_blank" rel="noreferrer">GitHub</a></li><li>Include your macOS version, Nicasa version, and detailed steps to reproduce the issue</li></ol><h2 id="system-information" tabindex="-1">System Information <a class="header-anchor" href="#system-information" aria-label="Permalink to &quot;System Information&quot;">​</a></h2><p>When reporting issues, please include:</p><ul><li>macOS version (Apple menu &gt; About This Mac)</li><li>Nicasa version (Nicasa &gt; About Nicasa)</li><li>Mac model and chip (Apple Silicon or Intel)</li><li>Steps to reproduce the issue</li><li>Any error messages</li></ul><p>This usually means the image file has been moved or deleted. Try reopening the folder or selecting a different directory.</p><h3 id="unsupported-format" tabindex="-1">&quot;Unsupported format&quot; <a class="header-anchor" href="#unsupported-format" aria-label="Permalink to &quot;&quot;Unsupported format&quot;&quot;">​</a></h3><p>The image format isn&#39;t recognized. Check our list of <a href="/guide/usage.html">supported formats</a> or convert the image to a compatible format.</p><h3 id="out-of-memory" tabindex="-1">&quot;Out of memory&quot; <a class="header-anchor" href="#out-of-memory" aria-label="Permalink to &quot;&quot;Out of memory&quot;&quot;">​</a></h3><p>Your system doesn&#39;t have enough RAM. Close other applications or upgrade your memory.</p><h2 id="advanced-troubleshooting" tabindex="-1">Advanced Troubleshooting <a class="header-anchor" href="#advanced-troubleshooting" aria-label="Permalink to &quot;Advanced Troubleshooting&quot;">​</a></h2><h3 id="view-logs" tabindex="-1">View Logs <a class="header-anchor" href="#view-logs" aria-label="Permalink to &quot;View Logs&quot;">​</a></h3><p>To access application logs:</p><ol><li>Go to Help &gt; Show Logs</li><li>Or find logs in: <ul><li>Windows: <code>%APPDATA%\\Nicasa\\logs</code></li><li>macOS: <code>~/Library/Application Support/Nicasa/logs</code></li><li>Linux: <code>~/.config/Nicasa/logs</code></li></ul></li></ol><h3 id="reset-application" tabindex="-1">Reset Application <a class="header-anchor" href="#reset-application" aria-label="Permalink to &quot;Reset Application&quot;">​</a></h3><p>To reset all settings to default:</p><ol><li>Close Nicasa</li><li>Delete the application data folder</li><li>Restart Nicasa</li></ol><h3 id="command-line-options" tabindex="-1">Command Line Options <a class="header-anchor" href="#command-line-options" aria-label="Permalink to &quot;Command Line Options&quot;">​</a></h3><p>For advanced users, Nicasa supports command line arguments:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nicasa</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Enable verbose logging</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nicasa</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reset-settings</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Reset all settings</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nicasa</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/folder</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Open specific folder</span></span></code></pre></div><h2 id="getting-more-help" tabindex="-1">Getting More Help <a class="header-anchor" href="#getting-more-help" aria-label="Permalink to &quot;Getting More Help&quot;">​</a></h2><p>If these solutions don&#39;t resolve your issue:</p><ol><li>Check our <a href="/guide/faq.html">FAQ</a></li><li>Search existing <a href="https://github.com/nicasa-project/nicasa-support/issues" target="_blank" rel="noreferrer">issues</a></li><li>Create a new issue with: <ul><li>Your operating system and version</li><li>Nicasa version</li><li>Steps to reproduce the problem</li><li>Any error messages or screenshots</li></ul></li></ol>`,68)])])}const g=i(s,[["render",r]]);export{d as __pageData,g as default};
